module thermal_sensor_calibration (
    input [3:0] raw_data,
    output [3:0] calibrated_data
);
    wire [4:0] temp_data; // 5 bits to accommodate overflow

      wire _n01 = raw_data[0] ^ 4'b0011[0];
  wire _c01 = raw_data[0] & 4'b0011[0];
  wire _n02 = raw_data[1] ^ 4'b0011[1] ^ _c01;
  wire _c02 = (raw_data[1] & 4'b0011[1]) | (raw_data[1] & _c01) | (4'b0011[1] & _c01);
  wire _n03 = raw_data[2] ^ 4'b0011[2] ^ _c02;
  wire _c03 = (raw_data[2] & 4'b0011[2]) | (raw_data[2] & _c02) | (4'b0011[2] & _c02);
  wire _n04 = raw_data[3] ^ 4'b0011[3] ^ _c03;
  wire _c04 = (raw_data[3] & 4'b0011[3]) | (raw_data[3] & _c03) | (4'b0011[3] & _c03);
  assign temp_data = {_n01, _n02, _n03, _n04}; // Add offset of 3
    assign calibrated_data = (temp_data > 4'b1111) ? 4'b1111 : temp_data[3:0]; // Cap at 15

endmodule
